mapper.select:
select user_id, phone, email, password, nickname, avatar, gender, student_id, school, dormitory, balance, credit_score, user_type, status, create_time, update_time
from users
where phone = #{phone}

select user_id, phone, email, password, nickname, avatar, gender, student_id, school, dormitory, balance, credit_score, user_type, status, create_time, update_time
from users
where user_id = #{userId}

select * from users


        and phone like concat('%', #{phone}, '%')


        and nickname like concat('%', #{nickname}, '%')


        and user_type = #{userType}


        and status = #{status}


order by create_time desc

select * from users


        and (
            phone like concat('%', #{keyword}, '%')
            or nickname like concat('%', #{keyword}, '%')
        )


        and user_type = #{userType}


        and status = #{status}


order by create_time desc
